var e=[{id:`L1_1`,type:`dialog`,speaker:`SPENCER_FLOOR_NULL_NULL`,text:{KOREA:`라울! 좌표는 얼마나 확보했지?!`,JPN:`ラウル！　確保した座標はいくつだ！？`,ENG:`Raúl! How many coordinates have you secured?!`,TWN:`拉烏爾！你找到了多少個座標？！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SPENCER_FLOOR_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:null}}},{id:`L2_1`,type:`dialog`,speaker:`RAUL_SCAVENGER_NULL_NULL`,text:{KOREA:`마흔 둘…? 아, 아니 마흔 하나!`,JPN:`42……？　い、いや、41！`,ENG:`Forty-two…? N-no, forty-one!`,TWN:`四十二個…？不，是四十一！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SPENCER_FLOOR_NULL_NULL`,face:`UNIT_SERIOUS`},C:{char_id:`RAUL_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_CUTSCEN_PHONE`},{id:`L3_1`,type:`dialog`,speaker:`SPENCER_FLOOR_NULL_NULL`,text:{KOREA:`좀 더 서두를 순 없어? 너희 대장도 슬슬 이제 한계인 것 같은데!`,JPN:`もう少し早くできないか？　あなたたちの隊長もそろそろ限界みたいだが。`,ENG:`Can't you be any faster? That captain looks like he's about to hit his limit!`,TWN:`不能再快一點嗎？你們的隊長也快撐不住了！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SPENCER_FLOOR_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`RAUL_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`RAUL_SCAVENGER_NULL_NULL`,text:{KOREA:`미치고 팔짝 뛸 소릴 하는군.`,JPN:`バカを言うんじゃねえよ。`,ENG:`This is insane.`,TWN:`你在說什麼瘋話。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SPENCER_FLOOR_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`RAUL_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`RAUL_SCAVENGER_NULL_NULL`,text:{KOREA:`신호기를 꽂아야 할 좌표가 한 두 개도 아니고 아흔 아홉 개나 되는데, 저 괴물 공격까지 피하면서 살아남으라니 주문이 과하잖아!`,JPN:`信号機を刺す座標が99個もあるってのに、あの化け物の攻撃を避けながら生き残れって注文が多すぎるじゃねえか！`,ENG:`You want me to plant beacons on ninety-nine coordinates while dodging that monster and survive? That's asking for a bit much, don't you think?!`,TWN:`要插上訊號器的座標又不是只有一兩個，足足有九十九個，還要一邊躲避怪物的攻擊，一邊活下來，要求也太高了！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SPENCER_FLOOR_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`RAUL_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`ROJO_SCAVENGER_NULL_NULL`,text:{KOREA:`5함 격침. 교란용 미끼도 다 떨어졌군.`,JPN:`5艦撃沈。かく乱用のエサも底をついたな。`,ENG:`Vessel Five's been taken out. We're out of bait too.`,TWN:`5號艦被擊沉。連用來當誘餌的傢伙都沒了。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SPENCER_FLOOR_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`RAUL_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`ROJO_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`}}},sfx:`FX_CUTSCEN_PHONE`},{id:`L9_1`,type:`dialog`,speaker:`RAUL_SCAVENGER_NULL_NULL`,text:{KOREA:`아, 저 겁쟁이 자식들. 기왕 당할 거면 괴물 쪽으로 떨어지라니깐.`,JPN:`ったく、ビビり野郎ども。どうせやられるなら化け物のほうに落ちろって。`,ENG:`Those gutless punks. If they were gonna go down anyway, they should've crashed into the damn thing.`,TWN:`啊，那些膽小鬼。既然都要被解決，就往怪物那邊掉啊。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SPENCER_FLOOR_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`RAUL_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`ROJO_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`}}},sfx:`FX_CUTSCEN_PHONE`},{id:`L10_1`,type:`dialog`,speaker:`RAUL_SCAVENGER_NULL_NULL`,text:{KOREA:`후발대는 아직 멀었나?!`,JPN:`後発隊はまだなのか！`,ENG:`Where's backup?!`,TWN:`後續部隊還沒來嗎？！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SPENCER_FLOOR_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`RAUL_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`ROJO_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:`좌표를 모두 확보하기 전엔 안 올 겁니다. 자칫하다간 작전의 핵심 열쇠를 잃을 수도 있으니까요.`,JPN:`座標をすべて確保するまでは来ないでしょう。下手をすれば作戦の要となる鍵を失うかもしれませんからね。`,ENG:`They won't move in until all coordinates are secured. If they rush in now, we risk losing the key to the whole operation.`,TWN:`在確保所有座標之前，他們是不會來的。否則作戰的關鍵就會遺失。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_IDLE`},C:{char_id:`RAUL_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`ROJO_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};